// ── Dropdown wrapper ──────────────────────────────────────────────────────

interface DropdownProps {
  id: string;
  label: string;
  icon: React.ReactNode;
  extraClass?: string;
  menuClass?: string;
  isOpen: boolean;
  onToggle: (id: string) => void;
  children: React.ReactNode;
}

function Dropdown({ id, label, icon, extraClass = '', menuClass = 'dropdown-menu', isOpen, onToggle, children }: DropdownProps) {
  return (
    <div className={`shop__filter-dropdown-item ${extraClass}`}>
      <div className="dropdown-toggle" onClick={() => onToggle(id)}>
        <div className="dropdown-toggle-inner">
          {icon}
          <span>{label}</span>
        </div>
        <div className={`dropdown-arrow${isOpen ? ' active' : ''}`}>
          <SvgArrow />
        </div>
      </div>
      <div className={menuClass} style={{ display: isOpen ? 'block' : 'none' }}>
        {children}
      </div>
    </div>
  );
}

// ── Main component ────────────────────────────────────────────────────────

interface Props {
  game: string;
  currentParams: Record<string, string>;
}

export default function ShopFilters({ game, currentParams }: Props) {
  const router = useRouter();
  const pathname = usePathname();
  const wrapRef = useRef<HTMLDivElement>(null);

  const PRICE_MIN = 0;
  const PRICE_MAX = 430;

  const [openDropdown, setOpenDropdown] = useState<string | null>(null);
  const [moreSubPanel, setMoreSubPanel] = useState<MoreSubPanel | null>(null);
  const [sliderMin, setSliderMin] = useState(() => parseInt(currentParams.min_price ?? '') || PRICE_MIN);
  const [sliderMax, setSliderMax] = useState(() => parseInt(currentParams.max_price ?? '') || PRICE_MAX);
  const [search, setSearch] = useState(currentParams.search ?? '');

  const priceSliderRef = useRef<HTMLDivElement>(null);
  const currentSliderMin = useRef(sliderMin);
  const currentSliderMax = useRef(sliderMax);
  currentSliderMin.current = sliderMin;
  currentSliderMax.current = sliderMax;
  const updateRef = useRef<(o: Record<string, string | undefined>) => void>(() => {});
  const pushPriceUrlRef = useRef<(min: number, max: number) => void>(() => {});

  useEffect(() => {
    setSliderMin(parseInt(currentParams.min_price ?? '') || PRICE_MIN);
    setSliderMax(parseInt(currentParams.max_price ?? '') || PRICE_MAX);
  }, [currentParams.min_price, currentParams.max_price]);

  useOutsideClick(wrapRef, () => {
    setOpenDropdown(null);
    setMoreSubPanel(null);
  });

  const toggleDropdown = useCallback((id: string) => {
    setOpenDropdown((prev) => {
      if (prev === id) { setMoreSubPanel(null); return null; }
      setMoreSubPanel(null);
      return id;
    });
  }, []);

  const update = useCallback((overrides: Record<string, string | undefined>) => {
    const next = { ...currentParams, ...overrides };
    Object.keys(next).forEach((k) => { if (!next[k]) delete next[k]; });
    delete next.page;
    // Close the dropdown synchronously *before* router.push so the close
    // commits on the current frame. router.push wraps the surrounding work
    // in a React transition in Next 16, which otherwise defers the state
    // change until the new page finishes streaming.
    flushSync(() => {
      setOpenDropdown(null);
      setMoreSubPanel(null);
    });
    router.push(`${pathname}?${new URLSearchParams(next as Record<string, string>).toString()}`);
  }, [currentParams, router, pathname]);
  updateRef.current = update;

  const pushPriceUrl = useCallback((min: number, max: number) => {
    const next = { ...currentParams };
    if (min <= PRICE_MIN) delete next.min_price; else next.min_price = String(min);
    if (max >= PRICE_MAX) delete next.max_price; else next.max_price = String(max);
    delete next.page;
    router.push(`${pathname}?${new URLSearchParams(next as Record<string, string>).toString()}`);
  }, [currentParams, router, pathname]);
  pushPriceUrlRef.current = pushPriceUrl;

  const toggleRegion   = (val: string) => update({ region: currentParams.region === val ? undefined : val });
  const toggleRank     = (val: string) => update({ rank: currentParams.rank === val ? undefined : val });
  const toggleSort     = (val: string) => update({ sort: val === 'recommended' ? undefined : val });
  const toggleCategory = (val: string) => update({ account_type: currentParams.account_type === val ? undefined : val });

  const applySearch = () => update({ search: search || undefined });

  const clearAll = () => {
    setSearch('');
    setSliderMin(PRICE_MIN);
    setSliderMax(PRICE_MAX);
    router.push(pathname);
  };

  const startThumbDrag = useCallback((thumb: 'left' | 'right') => (e: React.MouseEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    const slider = priceSliderRef.current;
    if (!slider) return;

    const getVal = (clientX: number) => {
      const { left, width } = slider.getBoundingClientRect();
      const pct = Math.max(0, Math.min(1, (clientX - left) / width));
      return Math.round(pct * (PRICE_MAX - PRICE_MIN) + PRICE_MIN);
    };

    const onMove = (ev: MouseEvent) => {
      const raw = getVal(ev.clientX);
      if (thumb === 'left') {
        setSliderMin(Math.max(PRICE_MIN, Math.min(raw, currentSliderMax.current - 1)));
      } else {
        setSliderMax(Math.min(PRICE_MAX, Math.max(raw, currentSliderMin.current + 1)));
      }
    };

    const onUp = () => {
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
      pushPriceUrlRef.current(currentSliderMin.current, currentSliderMax.current);
    };

    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  }, []);

  const currentSort = currentParams.sort ?? 'recommended';
  const currentSortLabel = SORT_OPTIONS.find((o) => o.value === currentSort)?.label ?? 'Recommended';

  const hasActiveFilters = !!(
    currentParams.region || currentParams.rank || currentParams.account_type ||
    currentParams.min_price || currentParams.max_price || currentParams.search
  );

  const showRank = game === 'valorant';

  return (
    <div ref={wrapRef}>
      <div className="shop__filter-wrap">

        {/* ── Left ── */}
        <div className="shop__filter-left">

          {/* Search */}
          <div className="shop__filter-search">
            <label htmlFor="shop-search">
              <svg width="22" height="22" viewBox="0 0 22 22" fill="none">
                <path d="M19.7368 18.7636L15.434 14.4616C16.6811 12.9643 17.303 11.0438 17.1703 9.09971C17.0375 7.15558 16.1604 5.33747 14.7213 4.02358C13.2822 2.7097 11.392 2.0012 9.44386 2.04547C7.49571 2.08975 5.63963 2.88339 4.26172 4.26129C2.88382 5.6392 2.09018 7.49528 2.0459 9.44343C2.00163 11.3916 2.71012 13.2818 4.02401 14.7209C5.33789 16.16 7.15601 17.0371 9.10013 17.1698C11.0443 17.3026 12.9647 16.6807 14.462 15.4335L18.764 19.7364C18.8007 19.6725 18.8514 19.5967 18.886 19.5133C18.9205 19.4298 18.9383 19.3403 18.9383 19.25C18.9383 19.1597 18.9205 19.0702 18.886 18.9868C18.8514 18.9033 18.8007 18.8275 18.7368 18.7636ZM3.43794 9.62501C3.43794 8.40124 3.80083 7.20495 4.48072 6.18742C5.16061 5.16989 6.12697 4.37683 7.25759 3.90851C8.3882 3.44019 9.6323 3.31766 10.8326 3.5564C12.0328 3.79515 13.1353 4.38445 14.0007 5.24979C14.866 6.11513 15.4553 7.21763 15.694 8.41789C15.9328 9.61815 15.8103 10.8622 15.3419 11.9929C14.8736 13.1235 14.0806 14.0898 13.063 14.7697C12.0455 15.4496 10.8492 15.8125 9.62544 15.8125C7.98497 15.8107 6.41221 15.1582 5.25223 13.9982C4.09224 12.8382 3.43976 11.2655 3.43794 9.62501Z" fill="currentColor" />
              </svg>
            </label>
            <input
              type="text"
              id="shop-search"
              placeholder="Search..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && applySearch()}
            />
          </div>

          <ul className="shop__filter-dropdown-wrap list-wrap">

            {/* Server */}
            <li>
              <Dropdown id="server" label="Server" icon={<SvgGlobe />} extraClass="shop__filter-server"
                isOpen={openDropdown === 'server'} onToggle={toggleDropdown}>
                <ul>
                  {REGIONS.map((r) => (
                    <li key={r.value}>
                      <div className="dropdown-check">
                        <label htmlFor={`region-${r.value}`}>{r.label}</label>
                        <input type="checkbox" id={`region-${r.value}`} className="form-check-input"
                          checked={currentParams.region === r.value} onChange={() => toggleRegion(r.value)} />
                      </div>
                    </li>
                  ))}
                </ul>
              </Dropdown>
            </li>

            {/* Rank — Valorant only */}
            {showRank && (
              <li>
                <Dropdown id="rank" label="Rank" icon={<SvgTrophy />} extraClass="shop__filter-rank"
                  isOpen={openDropdown === 'rank'} onToggle={toggleDropdown}>
                  <ul>
                    {VALORANT_RANKS.map((r) => (
                      <li key={r.value}>
                        <div className="dropdown-check">
                          <label htmlFor={`rank-${r.value}`}>
                            <img src={r.icon} alt={r.label} />
                            {r.label}
                          </label>
                          <input type="checkbox" id={`rank-${r.value}`} className="form-check-input"
                            checked={currentParams.rank === r.value} onChange={() => toggleRank(r.value)} />
                        </div>
                      </li>
                    ))}
                  </ul>
                </Dropdown>
              </li>
            )}

            {/* Price */}
            <li>
              <Dropdown id="price" label="Price" icon={<SvgPrice />} extraClass="shop__filter-price"
                menuClass="price-filter-wrap dropdown-menu"
                isOpen={openDropdown === 'price'} onToggle={toggleDropdown}>
                <div className="price-inputs">
                  <div className="min-price">
                    <span className="title">From</span>
                    <input type="text" readOnly value={`$${sliderMin}`} />
                  </div>
                  <span className="divider">-</span>
                  <div className="max-price">
                    <span className="title">To</span>
                    <input type="text" readOnly value={`$${sliderMax}`} />
                  </div>
                </div>
                <div className="slider" ref={priceSliderRef}>
                  <div className="track" />
                  <div
                    className="progress"
                    style={{
                      left: `${((sliderMin - PRICE_MIN) / (PRICE_MAX - PRICE_MIN)) * 100}%`,
                      width: `${((sliderMax - sliderMin) / (PRICE_MAX - PRICE_MIN)) * 100}%`,
                    }}
                  />
                  <div
                    className="thumb thumb-left"
                    style={{ left: `${((sliderMin - PRICE_MIN) / (PRICE_MAX - PRICE_MIN)) * 100}%` }}
                    onMouseDown={startThumbDrag('left')}
                  />
                  <div
                    className="thumb thumb-right"
                    style={{ left: `${((sliderMax - PRICE_MIN) / (PRICE_MAX - PRICE_MIN)) * 100}%` }}
                    onMouseDown={startThumbDrag('right')}
                  />
                </div>
                <div className="price-values">
                  <span>${sliderMin}</span>
                  <span>${sliderMax}</span>
                </div>
              </Dropdown>
            </li>

            {/* More Filter */}
            <li>
              <Dropdown id="more" label="More Filter" icon={<SvgMoreFilter />} extraClass="shop__filter-more"
                menuClass="shop__filter-menu dropdown-menu"
                isOpen={openDropdown === 'more'} onToggle={toggleDropdown}>
                {/* Main list — hidden with .hide when a sub-panel is active */}
                <ul className={`shop__filter-menu-wrap list-wrap${moreSubPanel ? ' hide' : ''}`}>
                  {MORE_PANELS.map((panel) => (
                    <li key={panel.id} className="menu-item" onClick={() => setMoreSubPanel(panel.id)}>
                      <div className="menu-item-inner">
                        {panel.icon}
                        {panel.label}
                      </div>
                      <span className="arrow"><SvgChevronRight /></span>
                    </li>
                  ))}
                </ul>

                {/* Sub-panels — always in DOM, shown with .active class */}
                {MORE_PANELS.map((panel) => (
                  <div key={panel.id} className={`menu-sub${moreSubPanel === panel.id ? ' active' : ''}`}>
                    <div className="menu-sub-top">
                      <span className="back-btn" onClick={(e) => { e.stopPropagation(); setMoreSubPanel(null); }}>
                        <SvgChevronLeft />
                      </span>
                      <span className="text">{panel.label}</span>
                    </div>
                    <ul className="list-wrap">
                      {CATEGORY_OPTIONS.map((opt) => (
                        <li key={opt.value}>
                          <div className="dropdown-check">
                            <label htmlFor={`${panel.id}-${opt.value}`}>{opt.label}</label>
                            <input
                              type="checkbox"
                              id={`${panel.id}-${opt.value}`}
                              className="form-check-input"
                              checked={currentParams.account_type === opt.value}
                              onChange={() => toggleCategory(opt.value)}
                            />
                          </div>
                        </li>
                      ))}
                    </ul>
                  </div>
                ))}
              </Dropdown>
            </li>

          </ul>
        </div>

        {/* ── Right — Sort ── */}
        <div className="shop__filter-right">
          <Dropdown id="sort" label={currentSortLabel} icon={<SvgStar />} extraClass="shop__filter-recommended"
            isOpen={openDropdown === 'sort'} onToggle={toggleDropdown}>
            <ul className="list-wrap">
              {SORT_OPTIONS.map((opt) => (
                <li key={opt.value}>
                  <div className="dropdown-check dropdown-check-two">
                    <label htmlFor={`sort-${opt.value}`} style={{ cursor: 'pointer' }}>
                      {opt.icon}
                      {opt.label}
                    </label>
                    <input type="checkbox" id={`sort-${opt.value}`} className="form-check-input"
                      checked={currentSort === opt.value} onChange={() => toggleSort(opt.value)} />
                    <span className="dot"></span>
                  </div>
                </li>
              ))}
            </ul>
          </Dropdown>

          {hasActiveFilters && (
            <button onClick={clearAll} className="border-btn"
              style={{ height: 46, padding: '0 16px', marginLeft: 8 }}>
              Clear
            </button>
          )}
        </div>

      </div>

      {/* Popular searches */}
      <div className="shop__popular-searches">
        <span className="title">Popular searches:</span>
        <ul className="list-wrap">
          {POPULAR_SEARCHES.map((term) => (
            <li key={term} style={{ cursor: 'pointer' }}
              onClick={() => { setSearch(term); update({ search: term }); }}>
              {term}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}
